('rusted-gear', 'Rusted Gear', 'Can be recycled into crafting materials.', 'Recyclable', 'Recyclable', 'Rare', 2000, NULL, 'https://assets.shiesty.me/items/rusted-gear.png', 'https://cdn.metaforge.app/arc-raiders/icons/rusted-gear.webp', NULL, 'Industrial', NULL, '["backpack","safePocket"]'::jsonb, '[]'::jsonb, '{"range":0,"damage":0,"health":0,"radius":0,"shield":0,"weight":3,"agility":0,"arcStun":0,"healing":0,"stamina":0,"stealth":0,"useTime":0,"duration":0,"fireRate":0,"stability":0,"stackSize":3,"damageMult":0,"raiderStun":0,"weightLimit":0,"augmentSlots":0,"healingSlots":0,"magazineSize":0,"reducedNoise":0,"shieldCharge":0,"backpackSlots":0,"quickUseSlots":0,"damagePerSecond":0,"movementPenalty":0,"safePocketSlots":0,"damageMitigation":0,"healingPerSecond":0,"reducedEquipTime":0,"staminaPerSecond":0,"increasedADSSpeed":0,"increasedFireRate":0,"reducedReloadTime":0,"illuminationRadius":0,"increasedEquipTime":0,"reducedUnequipTime":0,"shieldCompatibility":"","increasedUnequipTime":0,"reducedVerticalRecoil":0,"increasedBulletVelocity":0,"increasedVerticalRecoil":0,"reducedMaxShotDispersion":0,"reducedPerShotDispersion":0,"reducedDurabilityBurnRate":0,"reducedRecoilRecoveryTime":0,"increasedRecoilRecoveryTime":0,"reducedDispersionRecoveryTime":0}'::jsonb, '"<p>Rusted Gear is a rare resource in ARC Raiders used for Gunsmith level 3 upgrade. Rusted Gears spawn primarily inside vehicles with intact hoods and industrial containers across all maps.</p><p></p><p><strong>Best Rusted Gear Farming Locations:</strong></p><ul><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://metaforge.app/arc-raiders/map/dam\">Dam Battlegrounds</a> — The Controlled Access Zone currently has the highest Rusted Gear spawn rate in the game. Also check the buses and cars next to northern extract and service trucks in the Scrapyard.</p></li><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://metaforge.app/arc-raiders/map/blue-gate\">Blue Gate</a> — Checkpoint and Underground garage beneath the warehouse packed with searchable vehicles.</p></li><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://metaforge.app/arc-raiders/map/spaceport\">Spaceport</a> — Focus on rocket assembly and vehicle maintenance areas.</p></li><li><p><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://metaforge.app/arc-raiders/map/stella-montis\">Stella Montis</a> — Green breachable containers in the Loading Bay.</p></li></ul><p></p><p><strong>Tips to Maximize Rusted Gear Drops:</strong> Prioritize zones tagged \"Industrial\" on the map. Breach vehicles with closed hoods. Run night raids for higher spawn rates and better loot quality.</p>"'::jsonb, '{"id":"rusted-gear","name":"Rusted Gear","description":"Can be recycled into crafting materials.","item_type":"Recyclable","loadout_slots":["backpack","safePocket"],"icon":"https://cdn.metaforge.app/arc-raiders/icons/rusted-gear.webp","rarity":"Rare","value":2000,"workbench":null,"stat_block":{"range":0,"damage":0,"health":0,"radius":0,"shield":0,"weight":3,"agility":0,"arcStun":0,"healing":0,"stamina":0,"stealth":0,"useTime":0,"duration":0,"fireRate":0,"stability":0,"stackSize":3,"damageMult":0,"raiderStun":0,"weightLimit":0,"augmentSlots":0,"healingSlots":0,"magazineSize":0,"reducedNoise":0,"shieldCharge":0,"backpackSlots":0,"quickUseSlots":0,"damagePerSecond":0,"movementPenalty":0,"safePocketSlots":0,"damageMitigation":0,"healingPerSecond":0,"reducedEquipTime":0,"staminaPerSecond":0,"increasedADSSpeed":0,"increasedFireRate":0,"reducedReloadTime":0,"illuminationRadius":0,"increasedEquipTime":0,"reducedUnequipTime":0,"shieldCompatibility":"","increasedUnequipTime":0,"reducedVerticalRecoil":0,"increasedBulletVelocity":0,"increasedVerticalRecoil":0,"reducedMaxShotDispersion":0,"reducedPerShotDispersion":0,"reducedDurabilityBurnRate":0,"reducedRecoilRecoveryTime":0,"increasedRecoilRecoveryTime":0,"reducedDispersionRecoveryTime":0},"flavor