INSERT INTO "GameMap" ("mapId", "name", "slug", "goldmineKey", "description", "raw") VALUES
('stella-montis', 'Stella Montis', 'stella-montis', 'ID_GAMEMODE_LOCATION_MOUNTAINCOMPOUND', 'A secluded research facility amidst snow-draped peaks, Stella Montis is said to have been the last bulwark of humanity''s preservation.', '{"goldmineSection":"ST_GameModeLocations","goldmineKey":"ID_GAMEMODE_LOCATION_MOUNTAINCOMPOUND","description":"A secluded research facility amidst snow-draped peaks, Stella Montis is said to have been the last bulwark of humanity''s preservation."}'::jsonb),
('spaceport', 'Acerra Spaceport', 'spaceport', 'ID_GAMEMODE_LOCATION_SPACEPORT', 'Acerra Spaceport is a majestic testament to humanity''s past ambitions. This is where the Exodus shuttles, vessels of hope and desperation, once roared into the heavens, leaving a beleaguered Earth behind.', '{"goldmineSection":"ST_GameModeLocations","goldmineKey":"ID_GAMEMODE_LOCATION_SPACEPORT","description":"Acerra Spaceport is a majestic testament to humanity''s past ambitions. This is where the Exodus shuttles, vessels of hope and desperation, once roared into the heavens, leaving a beleaguered Earth behind."}'::jsonb),
('dam', 'Dam Battlegrounds', 'dam', 'ID_GAMEMODE_LOCATION_WATERTREATMENTFACILITY', 'Alcantara Power Plant, or "The Dam", stands as a silent sentinel amidst a toxic, waterlogged land, nourishing a riot of resilient vegetation and fauna. A monument echoing with the memories of power once generated.', '{"goldmineSection":"ST_GameModeLocations","goldmineKey":"ID_GAMEMODE_LOCATION_WATERTREATMENTFACILITY","description":"Alcantara Power Plant, or \"The Dam\", stands as a silent sentinel amidst a toxic, waterlogged land, nourishing a riot of resilient vegetation and fauna. A monument echoing with the memories of power once generated."}'::jsonb),
('buried-city', 'Buried City', 'buried-city', 'ID_GAMEMODE_LOCATION_BURIEDCITY', 'Amidst the sand dunes in this arid wasteland you will find a remnant of the old world quite unlike the cold steel spires of the Exodus age. Walk these narrow streets and empty plazas, and know that people once lived here.', '{"goldmineSection":"ST_GameModeLocations","goldmineKey":"ID_GAMEMODE_LOCATION_BURIEDCITY","description":"Amidst the sand dunes in this arid wasteland you will find a remnant of the old world quite unlike the cold steel spires of the Exodus age. Walk these narrow streets and empty plazas, and know that people once lived here."}'::jsonb),
('practice-range', 'Practice Range', 'practice-range', 'ID_GAMEMODE_LOCATION_PRACTICERANGE', 'Nestled in a secluded mountain hollow, the echoed gunshots from this practice range seem to confuse ARC''s sense of direction, creating a rare pocket of open-air safety. Raiders use the Backyard to hone their skills, and catch up on some long-overdue stargazing.', '{"goldmineSection":"ST_GameModeLocations","goldmineKey":"ID_GAMEMODE_LOCATION_PRACTICERANGE","description":"Nestled in a secluded mountain hollow, the echoed gunshots from this practice range seem to confuse ARC''s sense of direction, creating a rare pocket of open-air safety. Raiders use the Backyard to hone their skills, and catch up on some long-overdue stargazing."}'::jsonb),
('blue-gate', 'Blue Gate', 'blue-gate', 'ID_GAMEMODE_LOCATION_THEBLUEGATE', 'Once a steadfast symbol of defiant connection, the Blue Gate now serves as a daunting entryway into the perilous mountain ranges. The surrounding valley bears scars both new and old.', '{"goldmineSection":"ST_GameModeLocations","goldmineKey":"ID_GAMEMODE_LOCATION_THEBLUEGATE","description":"Once a steadfast symbol of defiant connection, the Blue Gate now serves as a daunting entryway into the perilous mountain ranges. The surrounding valley bears scars both new and old."}'::jsonb)
